lessons.theory:
## Exceptions
Handle errors gracefully.
```cpp
try {
    throw runtime_error("Error");
} catch (const exception& e) {
    cout << e.what();
}
```

lessons.starterCode:
#include <iostream>
#include <stdexcept>
using namespace std;

int main() {
    int divisor = 0;
    ___ {
        if (divisor == 0) ___ runtime_error("Div by zero");
    } ___ (const exception& e) {
        cout << e.___() << endl;
    }
    return 0;
}

lessons.solution:
#include <iostream>
#include <stdexcept>
using namespace std;
int main() {
    int divisor = 0;
    try {
        if (divisor == 0) throw runtime_error("Div by zero");
    } catch (const exception& e) {
        cout << e.what() << endl;
    }
    return 0;
}
